#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M,L; scanf("%d %d %d", &N, &M, &L);
        int *listId = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=M;i++){
            int K; scanf("%d", &K);
            for(int j=0;j<K;j++){
                int col; scanf("%d", &col);
                listId[col]=i;
            }
        }
        int prevId=-1, curId, segments=0;
        for(int i=0;i<L;i++){
            int col; scanf("%d", &col);
            curId = listId[col];
            if(i==0) segments=1; else if(curId!=prevId) segments++;
            prevId = curId;
        }
        printf("%d\n", segments);
        free(listId);
    }
    return 0;
}

