import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int L = fs.nextInt();
            int[] listId = new int[N + 1];
            for (int i = 1; i <= M; i++) {
                int K = fs.nextInt();
                for (int j = 0; j < K; j++) {
                    int col = fs.nextInt();
                    listId[col] = i;
                }
            }
            int segments = 0;
            int prev = -1;
            for (int i = 0; i < L; i++) {
                int col = fs.nextInt();
                int cur = listId[col];
                if (i == 0) segments = 1;
                else if (cur != prev) segments++;
                prev = cur;
            }
            sb.append(segments).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

