import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); L = int(next(it))
        list_id = [0] * (N + 1)
        for i in range(1, M + 1):
            K = int(next(it))
            for _ in range(K):
                col = int(next(it))
                list_id[col] = i
        segments = 0
        prev = -1
        for idx in range(L):
            col = int(next(it))
            cur = list_id[col]
            if idx == 0:
                segments = 1
            elif cur != prev:
                segments += 1
            prev = cur
        out_lines.append(str(segments))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

